CREATE TABLE IF NOT EXISTS "Airport" ("id" TEXT PRIMARY KEY, "iataCode" TEXT NOT NULL UNIQUE, "icaoCode" TEXT, "name" TEXT NOT NULL, "city" TEXT NOT NULL, "country" TEXT NOT NULL, "timezone" TEXT NOT NULL, "latitude" DOUBLE PRECISION NOT NULL, "longitude" DOUBLE PRECISION NOT NULL, "popularity" INTEGER NOT NULL DEFAULT 0, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "Airline" ("id" TEXT PRIMARY KEY, "iataCode" TEXT NOT NULL UNIQUE, "icaoCode" TEXT, "name" TEXT NOT NULL, "logoUrl" TEXT, "alliance" TEXT, "fleetInfo" JSONB, "rating" DECIMAL(65,30), "country" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "FlightSearch" ("id" TEXT PRIMARY KEY, "userId" TEXT, "searchHash" TEXT NOT NULL UNIQUE, "criteria" JSONB NOT NULL, "resultCount" INTEGER NOT NULL, "cheapestPrice" DECIMAL(65,30), "fastestMinutes" INTEGER, "provider" TEXT NOT NULL, "latencyMs" INTEGER NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "FlightCache" ("id" TEXT PRIMARY KEY, "cacheKey" TEXT NOT NULL UNIQUE, "payload" JSONB NOT NULL, "expiresAt" TIMESTAMP(3) NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "TrackedRoute" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL, "origin" TEXT NOT NULL, "destination" TEXT NOT NULL, "departureDate" TIMESTAMP(3) NOT NULL, "returnDate" TIMESTAMP(3), "currency" TEXT NOT NULL, "targetPrice" DECIMAL(65,30), "notifyOnDrop" BOOLEAN NOT NULL DEFAULT true, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "PriceHistory" ("id" TEXT PRIMARY KEY, "trackedRouteId" TEXT NOT NULL, "price" DECIMAL(65,30) NOT NULL, "currency" TEXT NOT NULL, "provider" TEXT NOT NULL, "observedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "PriceHistory_trackedRouteId_fkey" FOREIGN KEY ("trackedRouteId") REFERENCES "TrackedRoute"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "FavoriteRoute" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL, "origin" TEXT NOT NULL, "destination" TEXT NOT NULL, "name" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "FavoriteRoute_user_route_key" UNIQUE ("userId", "origin", "destination"));
CREATE TABLE IF NOT EXISTS "SearchAnalytics" ("id" TEXT PRIMARY KEY, "origin" TEXT NOT NULL, "destination" TEXT NOT NULL, "provider" TEXT NOT NULL, "resultCount" INTEGER NOT NULL, "latencyMs" INTEGER NOT NULL, "cacheHit" BOOLEAN NOT NULL, "searchedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
